class OverseasTerritory:
    def __init__(self, name):
        self.name = name
        self.uk_delegated_areas = []
        self.uk_reserved_areas = ['defence', 'internal_security', 'civil_aviation']

    def delegate_authority(self, areas):
        self.uk_delegated_areas.extend(areas)

    def conclude_treaty(self, area):
        if area in self.uk_reserved_areas:
            return "Requires UK Secretary of State authorization"
        elif area in self.uk_delegated_areas:
            return "Authority delegated to Premier/Ministers"
        else:
            return "Area not covered by delegation"

bvi = OverseasTerritory("British Virgin Islands")
bvi.delegate_authority([
    'tourism', 'taxation', 'eu_matters', 'caribbean_regional_affairs'
])
print(bvi.conclude_treaty('tourism'))  # Output: Authority delegated to Premier/Ministers
